import { cookies } from 'next/headers';
import { NextResponse, NextRequest } from 'next/server'
import { envConfig } from './configs/env.config';

const IS_PROD = process.env.NODE_ENV === 'production';
const publicPath = ['/auth']

export async function proxy(request: NextRequest) {
  const cookieStore = await cookies()
  const accessToken = cookieStore.get('access_token')
  const refreshToken = cookieStore.get('refresh_token')?.value
  const { pathname } = request.nextUrl;

  if (accessToken && publicPath.includes(pathname)) {
    return NextResponse.redirect(new URL('/', request.url))
  }

  if (!accessToken && refreshToken) {
    try {
      const res = await fetch(`${envConfig.NEXT_PUBLIC_API_URL}/api/auth/refresh-token`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refreshToken }),
      });

      const data = await res.json();

      if (!data.success) {
        const response = NextResponse.redirect(new URL('/auth', request.url))
        response.cookies.delete('refresh_token')
        return response
      }

      const response = NextResponse.redirect(request.url)
      response.cookies.set('access_token', data.data.accessToken, {
        httpOnly: true,
        secure: IS_PROD,
        maxAge: Number(envConfig.COOKIE_ACCESS_TOKEN_MAX_AGE) || 60 * 60 * 24 * 7,
        path: '/'
      })
      response.cookies.set('refresh_token', data.data.refreshToken, {
        httpOnly: true,
        secure: IS_PROD,
        maxAge: Number(envConfig.COOKIE_REFRESH_TOKEN_MAX_AGE) || 60 * 60 * 24 * 30,
        path: '/'
      })

      return response
    } catch {
      return NextResponse.redirect(new URL('/auth', request.url))
    }
  }

  return NextResponse.next()
}

export const config = {
  matcher: ['/', '/auth'],
}
